def make_topic(intro, subtopics, key_concepts, examples, quiz, hands_on=None, problems=None):
    s = {"introduction": intro, "subtopics": subtopics, "key_concepts": key_concepts, "examples": examples}
    return {"structured": s, "concept_quiz": quiz, "hands_on": hands_on or {"title":"Try it!","description":"Practice the concept above.","hint":"Use the examples as a guide.","code":""}, "problem_solving": problems or []}

